BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  ?elem vocab:NamedElement_name "APS%20Mission" .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  ?elem vocab:NamedElement_name "APS%20Conceptual" .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?type ?name WHERE {
  ?elem vocab:NamedElement_name "APS%20Mission%20Conceptual" .
  ?elem rdf:type ?type .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?inst ?classifier ?classifierName WHERE {
  ?inst rdf:type vocab:instance%20specification .
  ?inst vocab:NamedElement_name "post-Segment%20Exchange%20Duration%20Scenario.aps%20mission%20conceptual2.aps%2520conceptual.sh%20camera" .
  OPTIONAL { ?inst vocab:InstanceSpecification_classifier ?classifier .
    OPTIONAL { ?classifier vocab:NamedElement_name ?classifierName } }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?classifierName WHERE {
  ?inst rdf:type vocab:instance%20specification .
  OPTIONAL { ?inst vocab:InstanceSpecification_classifier ?classifier .
    OPTIONAL { ?classifier vocab:NamedElement_name ?classifierName } }
}
LIMIT 20

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?classifier ?name WHERE {
  ?classifier rdf:type vocab:block .
  FILTER(STR(?classifier) = "http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%20Packages::Telescope::WorkPackages::Control::Alignment%20and%20Phasing%20System::Systems%20Engineering::01%20Components::Operational::APS::Conceptual%20Design::Components::SH%20camera")
  OPTIONAL { ?classifier vocab:NamedElement_name ?name }
}
LIMIT 10

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?componentName WHERE {
  {
    SELECT DISTINCT (REPLACE(REPLACE(?instName, ".*\\.aps%20conceptual[0-9]*\\.aps%20conceptual\\.?", ""), "%20", " ") AS ?componentName) WHERE {
      ?inst rdf:type vocab:instance%20specification .
      ?inst vocab:NamedElement_name ?instName .
      FILTER(CONTAINS(STR(?instName), "aps%20conceptual"))
    }
  }
  FILTER(STRLEN(?componentName) > 3)
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?componentName (COUNT(*) as ?count) WHERE {
  {
    SELECT DISTINCT (REPLACE(REPLACE(?instName, ".*\\.aps%20conceptual[0-9]*\\.aps%20conceptual\\.([^.]+).*", "$1"), "%20", " ") AS ?componentName) WHERE {
      ?inst rdf:type vocab:instance%20specification .
      ?inst vocab:NamedElement_name ?instName .
      FILTER(CONTAINS(STR(?instName), "aps%20conceptual"))
    }
  }
}
GROUP BY ?componentName
ORDER BY DESC(?count)
LIMIT 30
